mapper.select:
SELECT id FROM ip_investment_pool WHERE id IN
#{id}
ORDER BY id ASC FOR UPDATE

mapper.update:
UPDATE ip_investment_pool
SET pool_name = #{poolName}
    ,market_codes = #{marketCodes}
    ,variety_codes = #{varietyCodes}
    ,hs_pool_name = #{hsPoolName}
    ,in_flow_id = #{inFlowId}
    ,in_flow_key = #{inFlowKey}
    ,in_flow_name = #{inFlowName}
    ,out_flow_id = #{outFlowId}
    ,out_flow_key = #{outFlowKey}
    ,out_flow_name = #{outFlowName}
    ,simple_in_flow_id = #{simpleInFlowId}
    ,simple_in_flow_key = #{simpleInFlowKey}
    ,simple_in_flow_name = #{simpleInFlowName}
    ,simple_out_flow_id = #{simpleOutFlowId}
    ,simple_out_flow_key = #{simpleOutFlowKey}
    ,simple_out_flow_name = #{simpleOutFlowName}
    ,batch_in_flow_id = #{batchInFlowId}
    ,batch_in_flow_key = #{batchInFlowKey}
    ,batch_in_flow_name = #{batchInFlowName}
    ,batch_out_flow_id = #{batchOutFlowId}
    ,batch_out_flow_key = #{batchOutFlowKey}
    ,batch_out_flow_name = #{batchOutFlowName}
    ,in_report_restriction = #{inReportRestriction}
    ,out_report_restriction = #{outReportRestriction}
    ,max_capacity = #{maxCapacity}
    ,lock_flag = #{lockFlag}
    ,frozen_period_in = #{frozenPeriodIn}
    ,outer_sort = #{outerSort}
    ,inner_sort = #{innerSort}
    ,description = #{description}
    ,updt_time = #{updtTime}
WHERE id = #{id}
  AND is_deleted = 0

mapper.select:
SELECT u.id ,u.name ,u.user_name ,u.dr ,u.ts AS crte_time ,u.ts AS updt_time ,GROUP_CONCAT(DISTINCT r.name ORDER BY r.id ASC SEPARATOR '、') AS roleName FROM ais_inv_analysis.t_sys_user u LEFT JOIN ais_inv_analysis.t_sys_user_role ur ON ur.user_id = u.id LEFT JOIN ais_inv_analysis.t_sys_role r ON r.id = ur.role_id AND r.enable = 1 WHERE u.dr = 0
AND EXISTS ( SELECT 1 FROM ais_inv_analysis.t_sys_user_role ur2 WHERE ur2.user_id = u.id AND ur2.role_id IN
#{roleId}
)
AND (u.name LIKE CONCAT('%', #{keyword}, '%') OR u.user_name LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY u.id ,u.name ,u.user_name ,u.dr ,u.ts ORDER BY u.id ASC
